SELECT u.id,u.first_name,u.last_name,u.first_name_en,u.last_name_en FROM user u LEFT JOIN user_role ur ON u.id = ur.user_id WHERE ur.role_id = 6 AND u.school_id = #{schoolId}
AND CONCAT(u.first_name, u.last_name) LIKE CONCAT(#{userKeywordRequest.fullName}, '%')
AND CONCAT(u.first_name_en, u.last_name_en) LIKE CONCAT(#{userKeywordRequest.fullNameEn}, '%')

SELECT u.id
FROM user u


        OR CONCAT(u.first_name, u.last_name) LIKE #{name}


        OR CONCAT(u.first_name_en, u.last_name_en) LIKE #{name}
